import java.util.*;

public class BFS {

    // Returns shortest path length from src to dest (-1 if unreachable)
    public static int shortestPath(Map<Integer, List<Integer>> graph, int src, int dest) {
        if (src == dest) return 0;

        Queue<Integer> queue   = new LinkedList<>();
        Set<Integer>   visited = new HashSet<>();

        queue.offer(src);
        visited.add(src);
        int steps = 0;

        while (!queue.isEmpty()) {
            int size = queue.size(); // process level by level
            steps++;
            for (int i = 0; i < size; i++) {
                int node = queue.poll();
                for (int neighbor : graph.getOrDefault(node, List.of())) {
                    if (neighbor == dest) return steps;
                    if (!visited.contains(neighbor)) {
                        visited.add(neighbor);
                        queue.offer(neighbor);
                    }
                }
            }
        }
        return -1; // unreachable
    }

    // Returns all nodes reachable from src
    public static List<Integer> reachable(Map<Integer, List<Integer>> graph, int src) {
        List<Integer> result  = new ArrayList<>();
        Queue<Integer> queue  = new LinkedList<>();
        Set<Integer>  visited = new HashSet<>();

        queue.offer(src);
        visited.add(src);

        while (!queue.isEmpty()) {
            int node = queue.poll();
            result.add(node);
            for (int neighbor : graph.getOrDefault(node, List.of())) {
                if (!visited.contains(neighbor)) {
                    visited.add(neighbor);
                    queue.offer(neighbor);
                }
            }
        }
        return result;
    }
}

import java.util.*;

public class DFS {

    // Recursive DFS — collects all nodes in traversal order
    public static void dfs(Map<Integer, List<Integer>> graph, int node,
                           Set<Integer> visited, List<Integer> order) {
        visited.add(node);
        order.add(node);
        for (int neighbor : graph.getOrDefault(node, List.of())) {
            if (!visited.contains(neighbor)) {
                dfs(graph, neighbor, visited, order);
            }
        }
    }

    // Cycle detection in directed graph (white=0, gray=1, black=2)
    public static boolean hasCycle(Map<Integer, List<Integer>> graph, int n) {
        int[] color = new int[n]; // 0=white, 1=gray, 2=black
        for (int i = 0; i < n; i++) {
            if (color[i] == 0 && dfsCycle(graph, i, color)) return true;
        }
        return false;
    }

    private static boolean dfsCycle(Map<Integer, List<Integer>> graph,
                                    int node, int[] color) {
        color[node] = 1; // gray — currently in recursion stack
        for (int neighbor : graph.getOrDefault(node, List.of())) {
            if (color[neighbor] == 1) return true;  // back edge = cycle
            if (color[neighbor] == 0 && dfsCycle(graph, neighbor, color)) return true;
        }
        color[node] = 2; // black — fully processed
        return false;
    }

    // Topological sort using DFS post-order
    public static List<Integer> topoSort(Map<Integer, List<Integer>> graph, int n) {
        boolean[] visited = new boolean[n];
        Deque<Integer> stack = new ArrayDeque<>();
        for (int i = 0; i < n; i++) {
            if (!visited[i]) topoHelper(graph, i, visited, stack);
        }
        List<Integer> result = new ArrayList<>();
        while (!stack.isEmpty()) result.add(stack.pop());
        return result;
    }

    private static void topoHelper(Map<Integer, List<Integer>> graph, int node,
                                   boolean[] visited, Deque<Integer> stack) {
        visited[node] = true;
        for (int nb : graph.getOrDefault(node, List.of())) {
            if (!visited[nb]) topoHelper(graph, nb, visited, stack);
        }
        stack.push(node); // push AFTER all neighbors processed (post-order)
    }
}

import java.util.*;

public class Dijkstra {

    // graph: adjacency list of [neighbor, weight] pairs
    public static int[] shortestPaths(List<int[]>[] graph, int src) {
        int n = graph.length;
        int[] dist = new int[n];
        Arrays.fill(dist, Integer.MAX_VALUE);
        dist[src] = 0;

        // Min-heap: [distance, node]
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
        pq.offer(new int[]{0, src});

        while (!pq.isEmpty()) {
            int[] curr = pq.poll();
            int d    = curr[0];
            int node = curr[1];

            if (d > dist[node]) continue; // stale entry — skip

            for (int[] edge : graph[node]) {
                int neighbor = edge[0];
                int weight   = edge[1];
                int newDist  = dist[node] + weight;

                if (newDist < dist[neighbor]) {
                    dist[neighbor] = newDist;
                    pq.offer(new int[]{newDist, neighbor});
                }
            }
        }
        return dist; // dist[i] = shortest distance from src to i
    }

    @SuppressWarnings("unchecked")
    public static void main(String[] args) {
        int n = 5;
        List<int[]>[] graph = new List[n];
        for (int i = 0; i < n; i++) graph[i] = new ArrayList<>();

        // Add edges: [from, to, weight]
        graph[0].add(new int[]{1, 4});
        graph[0].add(new int[]{2, 1});
        graph[2].add(new int[]{1, 2});
        graph[1].add(new int[]{3, 1});
        graph[2].add(new int[]{3, 5});

        int[] dist = shortestPaths(graph, 0);
        System.out.println(Arrays.toString(dist)); // [0, 3, 1, 4, MAX]
    }
}

public class UnionFind {
    private int[] parent;
    private int[] rank;
    private int components;

    public UnionFind(int n) {
        parent = new int[n];
        rank   = new int[n];
        components = n;
        for (int i = 0; i < n; i++) parent[i] = i;
    }

    // Path compression: flatten tree on every find
    public int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }

    // Union by rank: attach smaller tree under larger
    public boolean union(int x, int y) {
        int rx = find(x), ry = find(y);
        if (rx == ry) return false; // already connected

        if (rank[rx] < rank[ry])  parent[rx] = ry;
        else if (rank[rx] > rank[ry]) parent[ry] = rx;
        else { parent[ry] = rx; rank[rx]++; }

        components--;
        return true;
    }

    public boolean connected(int x, int y) { return find(x) == find(y); }
    public int countComponents() { return components; }

    // Example: number of distinct islands (connected components)
    public static int countIslands(int[][] grid) {
        int rows = grid.length, cols = grid[0].length;
        UnionFind uf = new UnionFind(rows * cols);
        int[] dr = {0, 1}, dc = {1, 0}; // right, down
        int water = 0;

        for (int r = 0; r < rows; r++) {
            for (int c = 0; c < cols; c++) {
                if (grid[r][c] == 0) { water++; continue; }
                for (int d = 0; d < 2; d++) {
                    int nr = r + dr[d], nc = c + dc[d];
                    if (nr < rows && nc < cols && grid[nr][nc] == 1)
                        uf.union(r * cols + c, nr * cols + nc);
                }
            }
        }
        return uf.countComponents() - water;
    }
}

import java.util.*;

public class TopologicalSort {

    // Kahn's Algorithm — BFS-based topological sort
    // Returns empty list if graph has a cycle
    public static List<Integer> kahnSort(int n, List<int[]> edges) {
        List<List<Integer>> adj     = new ArrayList<>();
        int[]               inDeg   = new int[n];

        for (int i = 0; i < n; i++) adj.add(new ArrayList<>());
        for (int[] e : edges) {
            adj.get(e[0]).add(e[1]);
            inDeg[e[1]]++;
        }

        Queue<Integer> queue = new LinkedList<>();
        for (int i = 0; i < n; i++) if (inDeg[i] == 0) queue.offer(i);

        List<Integer> result = new ArrayList<>();
        while (!queue.isEmpty()) {
            int node = queue.poll();
            result.add(node);
            for (int neighbor : adj.get(node)) {
                if (--inDeg[neighbor] == 0) queue.offer(neighbor);
            }
        }

        return result.size() == n ? result : List.of(); // empty = cycle
    }

    // Course Schedule — classic LeetCode problem
    public static boolean canFinish(int numCourses, int[][] prerequisites) {
        List<int[]> edges = new ArrayList<>();
        for (int[] pre : prerequisites) edges.add(new int[]{pre[1], pre[0]});
        return !kahnSort(numCourses, edges).isEmpty();
    }
}
